+async fn recv_text(ws: &mut TestServerWebSocket, context: &str) -> String {
+    let message = ws
+        .recv(&Cx::for_testing())
+        .await
+        .expect(context)
+        .unwrap_or_else(|| panic!("{context} missing"));
+    expect_text_message(message, context)
+}
